import { useMemo, useState } from 'react';
import { useNavigate } from 'react-router-dom';
import { Icon } from '@/components/Icon';
import { PageHeader } from '@/components/layout/PageHeader';
import { DataTable, type Column } from '@/components/data/DataTable';
import { EmptyState } from '@/components/data/EmptyState';
import { formatDateTime, formatNumber, formatRelativeTime } from '@/lib/format';
import { useTasksQuery, type TaskEntry, type TaskStatusFilter } from './queries';

const PAGE_SIZE = 25;
const GRID_TEMPLATE = '0.5fr 1.2fr 1.6fr 0.7fr 0.7fr 0.9fr 1.1fr';

export default function TasksListPage() {
  const [status, setStatus] = useState<TaskStatusFilter>('unresolved');
  const [page, setPage] = useState(0);
  const navigate = useNavigate();

  const { data, isLoading, isError, error, refetch } = useTasksQuery({ status, page, pageSize: PAGE_SIZE });

  const entries = data?.entries ?? [];
  const totalCount = data?.totalCount ?? 0;
  const totalPages = Math.max(1, Math.ceil(totalCount / PAGE_SIZE));

  const columns = useMemo<Column<TaskEntry>[]>(() => [
    { key: 'id', header: 'Id', render: t => <span className="muted mono">#{t.id}</span> },
    {
      key: 'created',
      header: 'Created',
      render: t => <span title={formatDateTime(t.createdAt)}>{formatRelativeTime(t.createdAt)}</span>,
    },
    {
      key: 'subscription',
      header: 'Subscription',
      render: t => (
        <div>
          <div style={{ fontWeight: 600, color: 'var(--text)' }}>{t.subscriptionName}</div>
          <div className="muted" style={{ fontSize: 12 }}>{t.queryName}</div>
        </div>
      ),
    },
    { key: 'latest', header: 'Latest', render: t => formatNumber(t.latestResultCount) },
    { key: 'execs', header: 'Execs', render: t => formatNumber(t.executionCount) },
    { key: 'unique', header: 'Unique', render: t => formatNumber(t.uniqueResultCounts) },
    {
      key: 'status',
      header: 'Status',
      render: t => t.resolved
        ? <span className="pill pill--ok">Resolved</span>
        : <span className="pill pill--warn">Unresolved</span>,
    },
  ], []);

  const onChangeStatus = (next: TaskStatusFilter) => {
    setStatus(next);
    setPage(0);
  };

  return (
    <div className="page">
      <PageHeader
        title="Tasks"
        sub={
          isLoading
            ? <span className="muted">Loading…</span>
            : <span className="muted">{formatNumber(totalCount)} {status} task{totalCount === 1 ? '' : 's'}</span>
        }
        actions={
          <button className="btn" type="button" onClick={() => refetch()} disabled={isLoading}>
            <Icon.Refresh size={14} className="btn__icon" />
            Refresh
          </button>
        }
      />

      <div className="card" style={{ padding: 12, marginBottom: 12, display: 'flex', gap: 8, alignItems: 'center' }}>
        <span className="muted" style={{ fontSize: 12, marginRight: 4 }}>Filter:</span>
        {(['unresolved', 'resolved', 'all'] as TaskStatusFilter[]).map(s => (
          <button
            key={s}
            type="button"
            className={'btn' + (status === s ? ' btn--primary' : '')}
            onClick={() => onChangeStatus(s)}
          >
            {s.charAt(0).toUpperCase() + s.slice(1)}
          </button>
        ))}
      </div>

      {isError && (
        <EmptyState
          icon={<Icon.Alert size={20} />}
          title="Failed to load tasks"
          description={error instanceof Error ? error.message : 'Unknown error'}
        />
      )}

      {!isError && (
        <div className="card" style={{ padding: 0 }}>
          <DataTable
            columns={columns}
            rows={entries}
            rowKey={t => t.id}
            gridTemplate={GRID_TEMPLATE}
            onRowClick={t => navigate(`/tasks/${t.id}`)}
            empty={
              <EmptyState
                icon={<Icon.Check size={20} />}
                title={isLoading ? 'Loading tasks…' : 'No tasks here'}
                description={isLoading ? '' : `No ${status === 'all' ? '' : status} tasks to show.`}
              />
            }
          />
        </div>
      )}

      {totalPages > 1 && (
        <div className="card" style={{ padding: 10, marginTop: 12, display: 'flex', justifyContent: 'space-between', alignItems: 'center' }}>
          <span className="muted" style={{ fontSize: 12 }}>
            Page {page + 1} of {totalPages}
          </span>
          <div style={{ display: 'flex', gap: 6 }}>
            <button className="btn" type="button" onClick={() => setPage(p => Math.max(0, p - 1))} disabled={page === 0 || isLoading}>
              Previous
            </button>
            <button className="btn" type="button" onClick={() => setPage(p => Math.min(totalPages - 1, p + 1))} disabled={page >= totalPages - 1 || isLoading}>
              Next
            </button>
          </div>
        </div>
      )}
    </div>
  );
}
